  1	import React, { FC, useEffect, useState } from 'react';
  2	import { useLocation } from 'react-router-dom-v5-compat';
  3	import classNames from 'classnames';
  4	
  5	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import BootOrderSummary from '@kubevirt-utils/components/BootOrder/BootOrderSummary';
  7	import BootOrderModal from '@kubevirt-utils/components/BootOrderModal/BootOrderModal';
  8	import FirmwareBootloaderModal from '@kubevirt-utils/components/FirmwareBootloaderModal/FirmwareBootloaderModal';
  9	import { BootMode } from '@kubevirt-utils/components/FirmwareBootloaderModal/utils/constants';
 10	import { getBootloaderTitleFromVM } from '@kubevirt-utils/components/FirmwareBootloaderModal/utils/utils';
 11	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 12	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 13	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 14	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 15	import { useToggle } from '@kubevirt-utils/hooks/useToggle';
 16	import { getName } from '@kubevirt-utils/resources/shared';
 17	import { getDisks, getInterfaces } from '@kubevirt-utils/resources/vm';
 18	import { updateCustomizeInstanceType } from '@kubevirt-utils/store/customizeInstanceType';
 19	import { ExpandableSection, Switch } from '@patternfly/react-core';
 20	import { printableVMStatus } from '@virtualmachines/utils';
 21	
 22	import { getSearchItemsIds } from '../../search/utils/utils';
 23	import { expandURLHash, getDetailsTabBootIds } from '../../utils/search';
 24	import { updateBootLoader, updatedBootOrder, updateStartStrategy } from '../utils/utils';
 25	
 26	type DetailsSectionBootProps = {
 27	  canUpdateVM: boolean;
 28	  instanceTypeVM?: V1VirtualMachine;
 29	  isCustomizeInstanceType?: boolean;
 30	  preferredBootmode?: BootMode;
 31	  vm: V1VirtualMachine;
 32	  vmi?: V1VirtualMachineInstance;
 33	};
 34	
 35	const DetailsSectionBoot: FC<DetailsSectionBootProps> = ({
 36	  canUpdateVM,
 37	  instanceTypeVM,
 38	  isCustomizeInstanceType,
 39	  preferredBootmode,
 40	  vm,
 41	  vmi,
 42	}) => {
 43	  const { t } = useKubevirtTranslation();
 44	  const { createModal } = useModal();
 45	  const location = useLocation();
 46	  const [isChecked, setIsChecked] = useState<boolean>(!!vm?.spec?.template?.spec?.startStrategy);
 47	  const [isExpanded, setIsExpanded] = useToggle('boot-management');
 48	  const vmName = getName(vm);
 49	
 50	  useEffect(() => {
 51	    expandURLHash(getSearchItemsIds(getDetailsTabBootIds(vm)), location?.hash, setIsExpanded);
 52	  }, [vm, location?.hash]);
 53	
 54	  return (
 55	    <ExpandableSection
 56	      isExpanded={isExpanded}
 57	      isIndented
 58	      onToggle={(_event, val) => setIsExpanded(val)}
 59	      toggleContent={<SearchItem id="boot-management">{t('Boot management')}</SearchItem>}
 60	    >
 61	      <VirtualMachineDescriptionItem
 62	        descriptionData={
 63	          <div className={classNames({ 'text-muted': !canUpdateVM })}>
 64	            {getBootloaderTitleFromVM(instanceTypeVM || vm, preferredBootmode)}
 65	          </div>
 66	        }
 67	        onEditClick={() =>
 68	          createModal(({ isOpen, onClose }) => (
 69	            <FirmwareBootloaderModal
 70	              onSubmit={(updatedVM) =>
 71	                isCustomizeInstanceType
 72	                  ? Promise.resolve(updateCustomizeInstanceType([{ data: updatedVM }]))
 73	                  : updateBootLoader(updatedVM, vm)
 74	              }
 75	              isOpen={isOpen}
 76	              onClose={onClose}
 77	              vm={instanceTypeVM || vm}
 78	              vmi={vmi}
 79	            />
 80	          ))
 81	        }
 82	        className="DetailsSection-margin__bottom"
 83	        data-test-id={`${vmName}-boot-method`}
 84	        descriptionHeader={<SearchItem id="boot-mode">{t('Boot mode')}</SearchItem>}
 85	        isEdit={canUpdateVM}
 86	      />
 87	      <VirtualMachineDescriptionItem
 88	        onEditClick={() =>
 89	          createModal((props) => (
 90	            <BootOrderModal
 91	              {...props}
 92	              onSubmit={(updatedVM: V1VirtualMachine) =>
 93	                isCustomizeInstanceType
 94	                  ? Promise.resolve(
 95	                      updateCustomizeInstanceType([
 96	                        {
 97	                          data: getDisks(updatedVM),
 98	                          path: `spec.template.spec.domain.devices.disks`,
 99	                        },
100	                        {
101	                          data: getInterfaces(updatedVM),
102	                          path: `.spec.template.spec.domain.devices.interfaces`,
103	                        },
104	                      ]),
105	                    )
106	                  : updatedBootOrder(updatedVM)
107	              }
108	              vm={vm}
109	              vmi={vmi}
110	            />
111	          ))
112	        }
113	        className="DetailsSection-margin__bottom"
114	        data-test-id={`${vmName}-boot-order`}
115	        descriptionData={<BootOrderSummary vm={vm} />}
116	        descriptionHeader={<SearchItem id="boot-order">{t('Boot order')}</SearchItem>}
117	        isEdit
118	      />
119	      <VirtualMachineDescriptionItem
120	        bodyContent={t(
121	          'Applying the start/pause mode to this Virtual Machine will cause it to partially reboot and pause.',
122	        )}
123	        descriptionData={
124	          <Switch
125	            onChange={(_event, checked) => {
126	              setIsChecked(checked);
127	              isCustomizeInstanceType
128	                ? Promise.resolve(
129	                    updateCustomizeInstanceType([
130	                      {
131	                        data: checked ? printableVMStatus.Paused : null,
132	                        path: `spec.template.spec.startStrategy`,
133	                      },
134	                    ]),
135	                  )
136	                : updateStartStrategy(checked, vm);
137	            }}
138	            id="start-in-pause-mode"
139	            isChecked={isChecked}
140	          />
141	        }
142	        descriptionHeader={
143	          <SearchItem id="start-pause-mode">{t('Start in pause mode')}</SearchItem>
144	        }
145	        className="DetailsSection-margin__bottom"
146	        data-test-id="start-pause-mode"
147	        isPopover
148	      />
149	    </ExpandableSection>
150	  );
151	};
152	
153	export default DetailsSectionBoot;

